import vex

@vex_client.guardrail(name="sec-disclaimer")
def validate_financial_output(output):
    disclaimer = "This is not financial advice. Consult a licensed professional."
    if "recommend" in output.lower() or "approve" in output.lower():
        if disclaimer not in output:
            return vex.Block("Missing SEC disclaimer")
    # Explainability check for credit decisions
    if "credit" in output.lower():
        vex_client.log_explanation({
            "decision": output,
            "model": "gemini-1.5-pro",
            "trace_id": vex_client.trace_id
        })
    return vex.Pass()

# Integrate with agent response handler
fraud_agent.add_postprocessor(validate_financial_output)

@vex_client.guardrail(name="pci-encryption")
def check_encrypted_transaction(tool_call):
    if "card_number" in tool_call.input:
        if not tool_call.input.get("encrypted", False):
            return vex.Block("PCI violation: unencrypted card data")
    # Verify TLS for payment gateway
    endpoint = tool_call.target
    if "payments" in endpoint and not endpoint.startswith("https"):
        return vex.Block("PCI violation: insecure endpoint")
    return vex.Pass()

# Register with ADK tool registry
payment_tool = AgentTool(
    name="process_payment",
    func=payment_func,
    pre_callback=check_encrypted_transaction
)
